import { test, expect } from '@playwright/test';
import path from 'path';
import { fileURLToPath } from 'url';
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/products.html')}`;
test.describe('Products Page', () => {
  test('should display page title and products list', async ({
    page
  }) => {
    await page.goto(localUrl);
    await expect(page).toHaveTitle('Products — AutoHeal Demo');
    const productHeadings = page.getByRole('heading', {
      name: /Product [A-Z]/
    });
    await expect(productHeadings).toHaveCount(3);
    await expect(productHeadings.nth(0)).toContainText('Product A');
    await expect(productHeadings.nth(1)).toContainText('Product B');
    await expect(productHeadings.nth(2)).toContainText('Product C');
  });
  test('should have all Add to Cart buttons visible and enabled', async ({
    page
  }) => {
    await page.goto(localUrl);
    const addButtons = page.getByRole('button', {
      name: 'Add to Cart'
    });
    await expect(addButtons).toHaveCount(3);
    for (let i = 0; i < 3; i++) {
      await expect(addButtons.nth(i)).toBeVisible();
      await expect(addButtons.nth(i)).toBeEnabled();
    }
  });
  test('should update cart count when adding products', async ({
    page
  }) => {
    await page.goto(localUrl);
    const cart = page.getByText(/Cart \(\d+\)/);
    await expect(cart).toHaveText('Cart (0)');
    const addButtons = page.getByRole('button', {
      name: 'Add to Cart'
    });
    await addButtons.nth(0).click();
    await expect(cart).toHaveText('Cart (1)');
    await addButtons.nth(1).click();
    await expect(cart).toHaveText('Cart (2)');
    await addButtons.nth(2).click();
    await expect(cart).toHaveText('Cart (3)');
  });
  test('should allow adding same product multiple times', async ({
    page
  }) => {
    await page.goto(localUrl);
    const cart = page.getByText(/Cart \(\d+\)/);
    const productAButton = page.getByRole('button', {
      name: 'Add to Cart'
    }).first();
    await productAButton.click();
    await expect(cart).toHaveText('Cart (1)');
    await productAButton.click();
    await expect(cart).toHaveText('Cart (2)');
    await productAButton.click();
    await expect(cart).toHaveText('Cart (3)');
  });
});
